import { 手勢, 指寬 } from './zhi.js';
function 豎合掌(bi, x, z, 比, 型) {
    const g = 型.鼓 ?? 0, 裂 = 型.裂 ?? 0, 交 = 型.交 ?? 0;
    const 中 = 手勢(bi, x, z, 比);
    // 一側之筆（鏡＝-1 左手先，+1 右手後——歸命右壓左之序）
    const 側 = (s) => {
        // 掌郭：外緣（腕→掌根鼓→小指根），鼓則腹脹
        s.骨(() => {
            s.M(1.88, 4.3);
            s.C(2.42 + 0.45 * g, 3.25, 2.52 + 0.5 * g, 1.9, 2.2 + 0.32 * g, 0.55);
            s.Qk(2.06 + 0.15 * g, -0.1, 1.72, -0.62);
            s.S();
        });
        // 指根之脊：小指根收向中根
        s.衣(() => { s.M(1.72, -0.62); s.Qk(1.2, -1.02, 0.62, -1.16); s.S(); });
        // 四指：後（小）→前（頭），逐指逐節——各守其道，梢相就而身不相犯
        const 斜 = (基) => 交 ? -(基 + 0.115) : -基 + 0.34 * g;
        const 角 = (末) => 交 ? [0, -0.02, -0.03]
            : [0, -0.36 * g, -0.34 * g + 末 * 0.42 * 裂];
        const 目 = [
            // [根x, 根z, 斜基, 節長, w根, w梢, 裂之與]
            [1.18, -0.62, 0.05, [1.55, 1.12, 0.82], 指寬.小根, 指寬.小梢, 0],
            [0.88, -0.98, 0.04, [1.95, 1.48, 1.05], 指寬.根, 指寬.梢, 1],
            [0.62, -1.18, 0.02, [2.18, 1.62, 1.16], 指寬.根, 指寬.梢, 1],
            [0.40, -1.08, 0.01, [1.92, 1.44, 1.0], 0.92, 0.70, 1],
        ];
        s.衣(() => {
            for (const [根a, 根b, 基, 長, w0, w1, 與] of 目) {
                const 鏈 = s.指(根a, 根b, -Math.PI / 2 + 斜(基), 長, 角(與));
                s.畫(鏈, w0, w1, { 紋: true, 甲: 與 > 0 && Math.abs(比) >= 2 && !交 });
            }
            // 拇指：並豎傍掌緣（歸命則橫交於掌前，右壓左）
            const 拇θ = 交 ? -Math.PI / 2 - 0.55 : -Math.PI / 2 - 0.16 + 0.30 * g;
            const 拇 = s.指(1.32, 2.45, 拇θ, 交 ? [1.95, 1.55] : [2.0, 1.62], 交 ? [0, -0.18] : [0, -0.05 - 0.30 * g]);
            s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        });
        // 腕：兩線近直而微斂，一紋橫繫（端開，沒於畫外）
        s.骨(() => { s.M(1.72, 4.55); s.L(1.9, 5.9); s.S(); s.M(0.45, 4.85); s.L(0.5, 5.95); s.S(); });
        s.細(() => { s.M(0.62, 5.05); s.Qk(1.1, 5.28, 1.62, 5.05); s.S(); });
    };
    側(手勢(bi, x, z, 比, -1));
    側(手勢(bi, x, z, 比, 1));
    // 掌根之底：一弧圓滿（兩掌之會）
    中.骨(() => { 中.M(-1.86, 4.32); 中.Qk(0, 4.88, 1.86, 4.32); 中.S(); });
    // 掌縫之相：五式各異
    中.細(() => {
        if (g > 0) { // 未敷蓮／初割蓮：腹脹如蕾，縫開兩弧
            中.M(0, -1.05);
            中.C(-0.95 * g, 0.4, -0.9 * g, 2.3, 0, 3.95);
            中.S();
            中.M(0, -1.05);
            中.C(0.95 * g, 0.4, 0.9 * g, 2.3, 0, 3.95);
            中.S();
        }
        else if (型.隙) { // 虛心：縫直而掌根現空（掌心虛）
            中.M(0, -1.05);
            中.L(0, 1.3);
            中.S();
            中.M(0, 1.3);
            中.C(-0.5, 2.15, -0.48, 3.2, 0, 3.9);
            中.S();
            中.M(0, 1.3);
            中.C(0.5, 2.15, 0.48, 3.2, 0, 3.9);
            中.S();
        }
        else if (交) { // 歸命：拇既橫交，縫短
            中.M(0, 0.35);
            中.Qk(0.05, 2.1, 0, 3.95);
            中.S();
        }
        else { // 堅實心：掌合無隙，一縫到底
            中.M(0, -1.05);
            中.Qk(0.05, 1.5, 0, 3.95);
            中.S();
        }
    });
}
// ── 十二合掌 · 豎五式 ────────────────────────────────────────────────────────
export const 堅實心合掌 = (bi, x, z, 比 = 1) => 豎合掌(bi, x, z, 比, {});
export const 虛心合掌 = (bi, x, z, 比 = 1) => 豎合掌(bi, x, z, 比, { 隙: 1 });
export const 未敷蓮合掌 = (bi, x, z, 比 = 1) => 豎合掌(bi, x, z, 比, { 鼓: 0.8 });
export const 初割蓮合掌 = (bi, x, z, 比 = 1) => 豎合掌(bi, x, z, 比, { 鼓: 0.5, 裂: 1 });
// 歸命合掌＝金剛合掌（十指頭交叉右壓左）：常用九印亦取此
export const 金剛合掌 = (bi, x, z, 比 = 1) => 豎合掌(bi, x, z, 比, { 交: 1 });
export function 仰掌橫(bi, x, z, 比, 鏡 = 1, 相 = {}) {
    const s = 手勢(bi, x, z, 比, 鏡);
    const 斂 = 相.斂 ?? 0;
    // 掌郭：近緣（拇側向觀者）與遠緣（小指側）
    s.骨(() => {
        s.M(-4.4, 1.2);
        s.C(-3.2, 2.0 + 0.2 * 斂, -1.8, 2.2 + 0.25 * 斂, -0.6, 1.85);
        s.S();
        s.M(-4.5, -0.75);
        s.C(-3.4, -1.15, -2.2, -1.2, -1.3, -1.0);
        s.S();
    });
    // 四指：橫臥四列（上小下頭——仰掌拇側向下），微垂而斂
    const 目 = [
        [-1.35, -0.95, [1.55, 1.1, 0.8], 指寬.小根, 指寬.小梢, false],
        [-1.15, -0.40, [1.95, 1.45, 1.0], 指寬.根, 指寬.梢, false],
        [-1.00, 0.25, [2.15, 1.6, 1.15], 指寬.根, 指寬.梢, true],
        [-0.85, 0.95, [1.9, 1.42, 1.0], 0.92, 0.70, false],
    ];
    s.衣(() => {
        for (const [根a, 根b, 長, w0, w1, 中] of 目) {
            const 直 = 相.中拄 && 中;
            // 中拄之式：餘指斂短讓中，中獨伸而拄
            const 節 = 直 ? [2.3, 1.7, 1.2] : 相.中拄 ? 長.map(v => v * 0.8) : 長;
            const 垂 = 直 ? [0, -0.02, -0.02]
                : [0, 0.07 + 0.3 * 斂 + (相.中拄 ? 0.12 : 0), 0.09 + 0.38 * 斂 + (相.中拄 ? 0.16 : 0)];
            const 鏈 = s.指(根a, 根b, 直 ? -0.03 : 0.03 + 0.1 * 斂, 節, 垂);
            s.畫(鏈, w0, w1, { 紋: true });
        }
        // 拇指
        if (相.拇 !== '無') {
            const 仰 = 相.拇 === '仰';
            const 鏈 = s.指(-2.9, 1.75, 仰 ? -1.15 : -0.5, [1.9, 1.5], 仰 ? [0, -0.2] : [0, 0.35]);
            s.畫(鏈, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
    });
    // 掌之丘壑：仰掌見紋
    s.細(() => {
        s.M(-3.6, 1.3);
        s.C(-2.6, 0.6, -1.9, 0.2, -1.35, -0.5);
        s.S();
        s.M(-3.9, 0.5);
        s.Qk(-3.0, -0.05, -2.2, -0.55);
        s.S();
    });
    // 腕：紋一道，臂二線近平相隨（端開向畫外）
    s.細(() => { s.M(-4.55, -0.5); s.Qk(-4.78, 0.3, -4.5, 1.05); s.S(); });
    s.骨(() => { s.M(-4.5, -0.85); s.L(-5.65, -0.72); s.S(); s.M(-4.4, 1.3); s.L(-5.6, 1.28); s.S(); });
}
// ── 覆掌橫：掌覆而指橫（鏡＝1 指向右）——覆手・反背之基；背見甲與腱 ──────────
export function 覆掌橫(bi, x, z, 比, 鏡 = 1, 相 = {}) {
    const s = 手勢(bi, x, z, 比, 鏡);
    // 背郭：上緣（頭指側——覆掌拇在遠）下緣（小指側）
    s.骨(() => {
        s.M(-4.4, -1.15);
        s.C(-3.1, -1.7, -1.9, -1.75, -0.85, -1.35);
        s.S();
        s.M(-4.5, 0.9);
        s.C(-3.4, 1.25, -2.3, 1.3, -1.4, 1.05);
        s.S();
    });
    // 掌骨之腱：背上淡扇
    s.細(() => {
        s.M(-3.7, -0.55);
        s.C(-2.7, -0.8, -1.9, -0.9, -1.2, -0.85);
        s.S();
        s.M(-3.7, 0.15);
        s.C(-2.8, 0.1, -2.0, 0.1, -1.35, 0.15);
        s.S();
    });
    // 四指：上頭下小（覆掌拇側在上遠），節顯而甲見
    const 目 = [
        [-0.95, -1.05, [1.9, 1.42, 1.0], 0.92, 0.70, false],
        [-0.90, -0.40, [2.15, 1.6, 1.15], 指寬.根, 指寬.梢, true],
        [-1.05, 0.25, [1.95, 1.45, 1.0], 指寬.根, 指寬.梢, false],
        [-1.25, 0.85, [1.55, 1.1, 0.8], 指寬.小根, 指寬.小梢, false],
    ];
    s.衣(() => {
        for (const [根a, 根b, 長, w0, w1, 中] of 目) {
            const 直 = 相.中拄 && 中;
            const 節 = 直 ? [2.3, 1.7, 1.2] : 相.中拄 ? 長.map(v => v * 0.8) : 長;
            const 鏈 = s.指(根a, 根b, 直 ? 0.0 : 0.04, 節, 直 ? [0, 0.02, 0.02] : [0, 0.09 + (相.中拄 ? 0.12 : 0), 0.12 + (相.中拄 ? 0.16 : 0)]);
            s.畫(鏈, w0, w1, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
        // 拇指：覆掌之拇沒於遠側，梢微出於上緣
        s.逸(() => { s.M(-2.3, -1.5); s.Qk(-1.7, -1.75, -1.15, -1.6); s.S(); });
    });
    // 腕
    s.細(() => { s.M(-4.5, -0.85); s.Qk(-4.72, 0.0, -4.45, 0.8); s.S(); });
    s.骨(() => { s.M(-4.45, -1.2); s.L(-5.6, -1.08); s.S(); s.M(-4.4, 1.0); s.L(-5.55, 0.95); s.S(); });
}
// ── 十二合掌 · 橫七式 ────────────────────────────────────────────────────────
// 顯露合掌：仰兩掌並列（小指緣相並），舒指如奉——顯露無藏
export function 顯露合掌(bi, x, z, 比 = 1) {
    for (const 鏡 of [-1, 1]) {
        const s = 手勢(bi, x, z, 比, 鏡);
        // 一手：掌仰而指上揚外分（自中線向外：小→頭之扇）
        s.骨(() => {
            s.M(0.42, 3.4);
            s.C(0.3, 1.9, 0.4, 0.6, 0.7, -0.5);
            s.S(); // 小指緣（中線側）
            s.M(1.5, 3.6);
            s.C(2.6, 3.1, 3.5, 2.1, 3.85, 0.9);
            s.S(); // 拇丘外緣
        });
        const 目 = [
            [0.85, -0.55, 0.02, [1.55, 1.1, 0.8], 指寬.小根, 指寬.小梢],
            [1.55, -0.9, 0.12, [1.95, 1.45, 1.0], 指寬.根, 指寬.梢],
            [2.35, -1.0, 0.22, [2.15, 1.6, 1.15], 指寬.根, 指寬.梢],
            [3.1, -0.8, 0.34, [1.9, 1.42, 1.0], 0.92, 0.70],
        ];
        s.衣(() => {
            for (const [根a, 根b, 斜, 長, w0, w1] of 目)
                s.畫(s.指(根a, 根b, -Math.PI / 2 + 斜, 長, [0, 0.05, 0.06]), w0, w1, { 紋: true });
            s.畫(s.指(3.75, 1.0, -Math.PI / 2 + 0.95, [1.9, 1.5], [0, 0.2]), 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        });
        // 指根之脊與掌紋（二道足矣，多則亂掌）
        s.細(() => {
            s.M(0.8, -0.35);
            s.C(1.6, -0.85, 2.5, -0.95, 3.2, -0.6);
            s.S();
            s.M(1.05, 1.5);
            s.C(1.9, 1.05, 2.7, 1.05, 3.3, 1.4);
            s.S();
        });
        // 腕
        s.骨(() => { s.M(0.5, 3.55); s.L(0.55, 4.85); s.S(); s.M(1.65, 3.7); s.L(1.75, 4.9); s.S(); });
        s.細(() => { s.M(0.68, 3.95); s.Qk(1.1, 4.18, 1.6, 4.0); s.S(); });
    }
    // 兩掌之會：小指緣相並一縫
    const 中 = 手勢(bi, x, z, 比);
    中.細(() => { 中.M(0, 3.3); 中.Qk(0.04, 1.4, 0, -0.4); 中.S(); });
}
// 持水合掌：仰掌相並而斂，十指如掬——若捧水獻尊
export function 持水合掌(bi, x, z, 比 = 1) {
    for (const 鏡 of [-1, 1]) {
        const s = 手勢(bi, x, z, 比, 鏡);
        s.骨(() => {
            s.M(0.42, 3.5);
            s.C(0.28, 2.2, 0.4, 1.1, 0.72, 0.1);
            s.S();
            s.M(1.55, 3.7);
            s.C(2.7, 3.2, 3.55, 2.2, 3.7, 0.9);
            s.S();
        });
        // 四指：內弧如掬，梢會於中線之上（碗口之相）
        const 目 = [
            [0.85, 0.0, -0.30, [1.5, 1.08, 0.78], 指寬.小根, 指寬.小梢],
            [1.6, -0.35, -0.22, [1.9, 1.42, 1.0], 指寬.根, 指寬.梢],
            [2.35, -0.4, -0.12, [2.1, 1.58, 1.12], 指寬.根, 指寬.梢],
            [3.0, -0.15, 0.0, [1.85, 1.4, 0.98], 0.92, 0.70],
        ];
        s.衣(() => {
            for (const [根a, 根b, 斜, 長, w0, w1] of 目)
                s.畫(s.指(根a, 根b, -Math.PI / 2 + 斜, 長, [0, -0.3, -0.34]), w0, w1, { 紋: true });
            // 拇指：沿外唇仰起內顧
            s.畫(s.指(3.55, 1.05, -Math.PI / 2 + 0.55, [1.85, 1.45], [0, -0.5]), 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        });
        s.細(() => {
            s.M(0.85, 0.25);
            s.C(1.6, -0.25, 2.4, -0.3, 3.0, 0.05);
            s.S();
            s.M(1.0, 1.3);
            s.C(1.8, 0.85, 2.6, 0.85, 3.2, 1.2);
            s.S();
        });
        s.骨(() => { s.M(0.5, 3.65); s.L(0.6, 4.85); s.S(); s.M(1.7, 3.8); s.L(1.9, 4.9); s.S(); });
    }
    const 中 = 手勢(bi, x, z, 比);
    中.細(() => { 中.M(0, 3.4); 中.Qk(0.04, 1.8, 0, 0.35); 中.S(); });
}
// 反叉合掌：兩手背相著，十指交叉（右加於左）——腕交如叉
export function 反叉合掌(bi, x, z, 比 = 1) {
    // 左手先（鏡-1 之勢自 +x 向 -x 上揚），右手後覆其上
    for (const 鏡 of [-1, 1]) {
        const s = 手勢(bi, x, z, 比, 鏡);
        // 手背：斜置，腕自下外來
        s.骨(() => {
            s.M(-2.9, 3.3);
            s.C(-2.5, 2.0, -1.7, 0.9, -0.55, 0.25);
            s.S(); // 背上緣
            s.M(-3.6, 4.15);
            s.C(-2.9, 3.55, -2.0, 2.75, -1.1, 2.15);
            s.S(); // 背下緣
        });
        // 四指：越中線而下垂於彼側（交叉之勢）
        const 目 = [
            [-0.5, 0.35, 0.55, [1.85, 1.4, 0.98], 0.92, 0.70],
            [-0.25, 0.75, 0.68, [2.1, 1.56, 1.12], 指寬.根, 指寬.梢],
            [-0.1, 1.25, 0.82, [1.9, 1.42, 1.0], 指寬.根, 指寬.梢],
            [0.0, 1.75, 0.96, [1.5, 1.08, 0.78], 指寬.小根, 指寬.小梢],
        ];
        s.衣(() => {
            for (const [根a, 根b, 斜, 長, w0, w1] of 目)
                s.畫(s.指(根a, 根b, 斜, 長, [0, 0.1, 0.12]), w0, w1, { 紋: true, 甲: Math.abs(比) >= 2 });
            // 拇指：立於背上緣之內
            s.畫(s.指(-1.5, 0.7, -0.85, [1.7, 1.35], [0, -0.25]), 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
        });
        s.細(() => { s.M(-3.3, 3.75); s.Qk(-3.0, 3.3, -2.75, 2.9); s.S(); });
        s.骨(() => { s.M(-3.7, 4.3); s.L(-4.35, 5.35); s.S(); s.M(-2.95, 3.45); s.L(-3.55, 4.5); s.S(); });
    }
}
// 反背互相著合掌：一仰一覆，兩背相著——下覆上仰，理事相依
export function 反背互相著合掌(bi, x, z, 比 = 1) {
    覆掌橫(bi, x, z + 1.9 * 比, 比, 1); // 下手覆，指向右
    仰掌橫(bi, x, z - 1.7 * 比, 比, -1, { 拇: '傍' }); // 上手仰，指向左，背著下背
}
// 橫拄指合掌：仰兩掌，二中指頭相拄——橫而相接
export function 橫拄指合掌(bi, x, z, 比 = 1) {
    仰掌橫(bi, x - 3.3 * 比, z, 比, 1, { 中拄: true, 拇: '傍' });
    仰掌橫(bi, x + 3.3 * 比, z, 比, -1, { 中拄: true, 拇: '傍' });
}
// 覆手向下合掌：覆兩掌並列，二拇指並而相接，指頭向前
export function 覆手向下合掌(bi, x, z, 比 = 1) {
    for (const 鏡 of [-1, 1]) {
        const s = 手勢(bi, x, z, 比, 鏡);
        // 手背斜覆：腕自下來，指向前上（縮觀）
        s.骨(() => {
            s.M(0.55, 2.0);
            s.C(0.5, 1.0, 0.7, 0.1, 1.15, -0.55);
            s.S(); // 內緣（拇側）
            s.M(2.9, 2.6);
            s.C(3.5, 1.8, 3.8, 0.9, 3.7, 0.0);
            s.S(); // 外緣（小指側）
        });
        // 拇指：沿內緣向前，兩拇於中線相並
        s.衣(() => {
            s.畫(s.指(0.95, 1.3, -Math.PI / 2 - 0.28, [1.7, 1.4], [0, 0.1]), 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
            // 四指：向前微扇，背見其節
            const 目 = [
                [1.5, -0.6, -0.1, [1.85, 1.4, 0.98], 0.92, 0.70],
                [2.2, -0.65, 0.0, [2.05, 1.55, 1.1], 指寬.根, 指寬.梢],
                [2.9, -0.5, 0.1, [1.9, 1.42, 1.0], 指寬.根, 指寬.梢],
                [3.5, -0.2, 0.22, [1.5, 1.08, 0.78], 指寬.小根, 指寬.小梢],
            ];
            for (const [根a, 根b, 斜, 長, w0, w1] of 目)
                s.畫(s.指(根a, 根b, -Math.PI / 2 + 斜, 長, [0, 0.08, 0.1]), w0, w1, { 紋: true, 甲: Math.abs(比) >= 2 });
        });
        // 背之腱
        s.細(() => {
            s.M(1.6, 1.3);
            s.C(1.8, 0.6, 1.9, 0.1, 1.85, -0.35);
            s.S();
            s.M(2.5, 1.5);
            s.C(2.7, 0.8, 2.75, 0.25, 2.6, -0.3);
            s.S();
        });
        s.骨(() => { s.M(0.75, 2.3); s.L(1.0, 3.5); s.S(); s.M(2.85, 2.75); s.L(2.6, 3.9); s.S(); });
        s.細(() => { s.M(1.1, 2.6); s.Qk(1.8, 2.95, 2.5, 2.85); s.S(); });
    }
}
// 覆手合掌：覆兩掌相向，二中指頭相接
export function 覆手合掌(bi, x, z, 比 = 1) {
    覆掌橫(bi, x - 3.3 * 比, z, 比, 1, { 中拄: true });
    覆掌橫(bi, x + 3.3 * 比, z, 比, -1, { 中拄: true });
}
